-
-/* 
-  ========================================
-  SOPHISTICATED BACKGROUND SYSTEM
-  ========================================
-*/
-
-/* Base noise texture for "film grain" feel - Refined opacity */
-body::before {
-  content: "";
-  position: fixed;
-  inset: 0;
-  z-index: -1;
-  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.8' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)' opacity='0.03'/%3E%3C/svg%3E");
-  opacity: 0.4;
-  pointer-events: none;
-  mix-blend-mode: overlay;
-}
-
-/* Deep ambient gradients - More localized and subtle */
-body::after {
-  content: "";
-  position: fixed;
-  top: 0;
-  left: 0;
-  width: 100%;
-  height: 100%;
-  z-index: -2;
-  background: 
-    radial-gradient(circle at 15% 15%, rgba(56, 189, 248, 0.04), transparent 45%),
-    radial-gradient(circle at 85% 25%, rgba(124, 58, 237, 0.04), transparent 45%),
-    linear-gradient(to bottom, #020617, #0B1120);
-  pointer-events: none;
-}
-
-/* 
-  ========================================
-  TYPOGRAPHY UTILITIES
-  ========================================
-*/
-
-/* WORLD CLASS EDITORIAL TYPOGRAPHY */
-
-.prose {
-  /* Optimal reading width */
-  max-width: 68ch; 
-  font-family: var(--font-serif-stack);
-  color: #cbd5e1; /* Slate-300 - slightly softer than pure white */
-  font-size: 1.125rem; /* 18px base size for better readability */
-  line-height: 1.75;
-}
-
-/* Paragraphs - The Rhythm */
-.prose p {
-  margin-bottom: 1.5em; /* Critical: Space between paragraphs */
-  margin-top: 0;
-  text-wrap: pretty;
-}
-
-/* Headings - The Structure */
-.prose h1, 
-.prose h2, 
-.prose h3, 
-.prose h4 {
-  font-family: var(--font-sans);
-  color: #f1f5f9; /* Slate-100 */
-  font-weight: 600;
-  letter-spacing: -0.02em;
-  line-height: 1.3;
-}
-
-.prose h2 {
-  margin-top: 3em; /* Huge breathing room before new sections */
