-}
-
-/* Lists - The Detail */
-.prose ul, 
-.prose ol {
-  margin-top: 1em;
-  margin-bottom: 1.5em;
-  padding-left: 1.5em;
-}
-
-.prose li {
-  margin-bottom: 0.6em; /* Space between list items */
