-  font-feature-settings: "tnum";
-}
-
-/* Quotes - The Emphasis */
-.prose blockquote {
-  margin: 2.5em 0;
-  padding: 1em 1.5em;
-  border-left: 3px solid #38bdf8; /* Sky-400 highlight */
