-  color: transparent;
-}
-
-/* 
-  ========================================
-  GLASSMORPHISM & DEPTH 
-  ========================================
-*/
-
-/* Lighter, cleaner glass panel */
-.glass-panel {
-  background: rgba(2, 6, 23, 0.4);
