-}
-
-.glass-card:hover {
-  background: rgba(15, 23, 42, 0.5);
-  border-color: rgba(255, 255, 255, 0.08);
-  transform: translateY(-2px);
-  box-shadow: 
-    0 0 0 1px rgba(255,255,255,0.05),
-    0 12px 32px -8px rgba(0,0,0,0.4),
